#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e3+5,dx[]={-1,0,1,0},dy[]={0,1,0,-1};
int n,m,vis[MAXN][MAXN];
char g[MAXN][MAXN];
PII boy,girl,ghost[2];
bool check(int x,int y,int tim)
{
	if(x<1||x>n||y<1||y>m||g[x][y]=='X')
	{
		return false;
	}
	FOR(i,0,1)
	{
		if(abs(x-ghost[i].fst)+abs(y-ghost[i].snd)<=tim*2)
		{
			return false;
		}
	}
	return true;
}
int bfs()
{
	int tim=0;
	memset(vis,0,sizeof vis);
	queue<PII> qb,qg;
	qb.push(boy);
	qg.push(girl);
	wh(qb.size()||qg.size())
	{
		++tim;
        FOR(i,0,2)
        {
            int bs=qb.size()-1;
            FOR(i,0,bs)
    		{
    			PII t=qb.front();
    			qb.pop();
    			int x=t.fst,y=t.snd;
    			if(!check(x,y,tim))
    			{
    				continue;
    			}
    			FOR(k,0,3)
    			{
    				int a=x+dx[k],b=y+dy[k];
    				if(check(a,b,tim))
    				{
    					if(vis[a][b]==2) 
    					{
    						return tim;	
    					}
    					if(!vis[a][b])
    					{
    						vis[a][b]=1;
    						qb.push({a,b});
    					}
    				}
    			}
    		}
        }

		FOR(i,0,0)
		{
            int gs=qg.size()-1;
			FOR(j,0,gs)
			{
				PII t=qg.front();
				qg.pop();
				int x=t.fst,y=t.snd;
				if(!check(x,y,tim))
				{
					continue;
				}
				FOR(k,0,3)
				{
					int a=x+dx[k],b=y+dy[k];
					if(check(a,b,tim))
					{
						if(vis[a][b]==1)
						{
							return tim;
						}
						if(!vis[a][b])
						{
							vis[a][b]=2;
							qg.push({a,b});
						}
					}
				}
			}			
		}
	}
	return -1;
}
signed main(void)
{
	ROF(t,read(),1)
	{
		n=read(),m=read();
		FOR(i,1,n)
		{
			FOR(j,1,m)
			{
				cin>>g[i][j];
			}
		}
		int cnt=0;
		FOR(i,1,n)
		{
			FOR(j,1,m)
			{
				if(g[i][j]=='M')boy={i,j};
				if(g[i][j]=='G')girl={i,j};
				if(g[i][j]=='Z')ghost[cnt++]={i,j};
			}
		}
		writeln(bfs());
	}
	return false;
}
